def list_markets(query: dict[str, list[str]]) -> tuple[dict[str, Any], int]:
    """Return the market collection with optional status, sort, and search filters."""
    # Parse status param
    statuses = query.get("status", [])
    if len(statuses) > 1:
        raise ApiError(
            400,
            "invalid_query",
            "status must be provided at most once",
            {"parameter": "status", "received": statuses},
        )
    status = statuses[0] if statuses else None
    status_all = status == "all"
    if status_all:
        status = None
    elif status is not None and status not in ALLOWED_MARKET_STATUSES:
        raise ApiError(
            400,
            "invalid_query",
            "status must be one of the supported market states",
            {"parameter": "status", "received": status, "allowed": sorted(ALLOWED_MARKET_STATUSES | {"all"})},
        )

    # Parse sort param
    sorts = query.get("sort", [])
    if len(sorts) > 1:
        raise ApiError(
            400,
            "invalid_query",
            "sort must be provided at most once",
            {"parameter": "sort", "received": sorts},
        )
    sort = sorts[0] if sorts else None
    if sort is not None and sort not in ALLOWED_MARKET_SORTS:
        raise ApiError(
            400,
            "invalid_query",
            "sort must be one of the supported sort orders",
            {"parameter": "sort", "received": sort, "allowed": sorted(ALLOWED_MARKET_SORTS)},
        )

    # Parse q (title search) param
    queries = query.get("q", [])
    if len(queries) > 1:
        raise ApiError(
            400,
            "invalid_query",
            "q must be provided at most once",
            {"parameter": "q", "received": queries},
        )
    title_query = queries[0].strip() if queries else None
    if title_query == "":
        title_query = None

    include_resolved = parse_boolean_query_param(query, "include_resolved", default=False)

    # Build result set
    markets = list(MARKETS.values())
    effective_include_resolved = include_resolved or status == "resolved" or status_all
    if not effective_include_resolved:
        markets = [market for market in markets if market["status"] != "resolved"]
    if status is not None:
        markets = [market for market in markets if market["status"] == status]
    if title_query is not None:
        needle = title_query.casefold()
        markets = [market for market in markets if needle in str(market["title"]).casefold()]

    # Apply sorting
    if sort == "volume":
        markets = sorted(markets, key=lambda m: float(m.get("volume", 0)), reverse=True)
    elif sort == "liquidity":
        markets = sorted(markets, key=lambda m: float(m.get("liquidity", 0)), reverse=True)
    elif sort == "created":
        markets = sorted(markets, key=lambda m: str(m.get("created_at", "")), reverse=True)

    summaries = [market_summary(market) for market in markets]
    filters = {"status": status, "include_resolved": effective_include_resolved}
    if sort:
        filters["sort"] = sort
    if title_query:
        filters["q"] = title_query
    return {
        "markets": summaries,
        "count": len(summaries),
        "meta": make_meta(filters=filters),
    }, 200


def create_market(body: dict[str, Any] | None) -> tuple[dict[str, Any], int]:
    """Create a new market from a POST payload."""
    if not body:
        raise ApiError(400, "invalid_payload", "Request body is required")

    title = body.get("title")
    description = body.get("description", "")
    outcomes = body.get("outcomes")
    expires_at = body.get("expires_at")
    liquidity = body.get("liquidity", 10000.0)
    max_pos_size = body.get("maxPositionSize")

    if not title or not isinstance(title, str):
        raise ApiError(400, "invalid_payload", "title is required and must be a string")
    if not outcomes or not isinstance(outcomes, list) or len(outcomes) < 2:
        raise ApiError(400, "invalid_payload", "outcomes must be a list with at least 2 entries")
    for o in outcomes:
        if not isinstance(o, dict) or "id" not in o or "name" not in o:
            raise ApiError(400, "invalid_payload", "each outcome must have id and name")
    if not expires_at or not isinstance(expires_at, str):
        raise ApiError(400, "invalid_payload", "expires_at is required (ISO 8601 string)")
    try:
        parsed_expires = datetime.fromisoformat(expires_at.replace("Z", "+00:00"))
    except (ValueError, TypeError):
        raise ApiError(400, "invalid_payload", "expires_at must be a valid ISO 8601 datetime")
    if parsed_expires <= datetime.now(timezone.utc):
        raise ApiError(400, "invalid_payload", "expires_at must be in the future")
    if not isinstance(liquidity, (int, float)) or liquidity <= 0:
        raise ApiError(400, "invalid_payload", "liquidity must be a positive number")
    for o in outcomes:
        name = o.get("name", "")
        if not isinstance(name, str) or not name.strip():
            raise ApiError(400, "invalid_payload", "each outcome name must be a non-empty string")
    if max_pos_size is not None:
        if not isinstance(max_pos_size, (int, float)) or max_pos_size <= 0:
            raise ApiError(400, "invalid_payload", "maxPositionSize must be a positive number")

    # Check for duplicate outcome IDs
    outcome_ids = [o["id"] for o in outcomes]
    if len(outcome_ids) != len(set(outcome_ids)):
        raise ApiError(400, "invalid_payload", "outcome IDs must be unique")

    # Generate variable ID from title
    variable_id = title.lower().replace(" ", "_")[:40]
    existing_market = next(
        (market for market in MARKETS.values() if str(market.get("variableId")) == variable_id),
        None,
    )
    if existing_market is not None:
        raise ApiError(
            409,
            "market_already_exists",
            "A market with this title already exists",
            {
                "title": title,
                "variableId": variable_id,
                "existingMarketId": str(existing_market["id"]),
            },
        )

    # Generate market ID
    market_num = len(MARKETS) + 1
    market_id = f"m{market_num}"
    while market_id in MARKETS:
        market_num += 1
        market_id = f"m{market_num}"

    # Uniform prior
    uniform_p = round(1.0 / len(outcomes), 6)
    marginals = {}
    for i, o in enumerate(outcomes):
        if i < len(outcomes) - 1:
            marginals[o["id"]] = uniform_p
        else:
            marginals[o["id"]] = round(1.0 - uniform_p * (len(outcomes) - 1), 6)

    now = datetime.now(timezone.utc).isoformat().replace("+00:00", "Z")
    market: dict[str, Any] = {
        "id": market_id,
        "title": title,
        "description": description,
        "variableId": variable_id,
        "status": "active",
        "outcomes": [{"id": o["id"], "name": o["name"]} for o in outcomes],
        "marginals": marginals,
        "liquidity": float(liquidity),
        "volume": 0.0,
        "created_at": now,
        "expires_at": expires_at,
    }
    if max_pos_size is not None:
        market["maxPositionSize"] = float(max_pos_size)

    MARKETS[market_id] = market
    ensure_market_engine_state(market_id)

    genesis_event = emit_market_created_event(market_id, market)

    return {
        "market": deepcopy(market),
        "event": deepcopy(genesis_event),
        "meta": make_meta(),
    }, 201


